package kotlinx.coroutines

import kotlin.coroutines.*
import kotlin.test.*

class CoroutineContextIsActiveTest : TestBase() {

    @Test
    fun testIsActiveWithNoJobDefaultsToTrue() {
        assertTrue(EmptyCoroutineContext.isActive)
        assertTrue(CoroutineName("test").isActive)
    }

    @Test
    fun testIsActiveDelegatesToJob() {
        val job = Job()
        val ctx: CoroutineContext = job + CoroutineName("test")
        assertTrue(ctx.isActive)

        job.cancel()
        assertFalse(ctx.isActive)
    }
}
